  def __init__(self):
          # Optimized schedule leveraging parallelism and resource constraints
          self.worker_config = [
              # Partition 1 on node-a: Heavy jobs split for parallel execution
              {
                  "node": "node-a-8core",
                  "cores": "0-3",
                  "threads": 4,
                  "jobs": ["streamcluster", "freqmine"]
              },
              # Partition 2 on node-a: Remaining heavy jobs
              {
                  "node": "node-a-8core",
                  "cores": "4-7",
                  "threads": 4,
                  "jobs": ["canneal", "blackscholes", "vips", "barnes"]
              },
              # Partition 3 on node-b: Light jobs that won't interfere with memcached
              {
                  "node": "node-b-4core",
                  "cores": "0-2",
                  "threads": 3,
                  "jobs": ["radix"]
              }
          ]
